// Complex Matrix and Quaternion Math 1
vector up = normalize(@v + set(0,0.1,0));
vector dir = set(0,1,0);
matrix3 rot = maketransform(dir, up);
rotate(rot, @Time * 4.59, up);
vector4 q1 = quaternion(rot);
vector4 q2 = eulertoquaternion(set(@ptnum * 0.1, @Time, 0), 0);
@orient = slerp(q1, qmultiply(q1, q2), 0.5);
matrix xform = ident(); translate(xform, @P); scale(xform, set(4.59,4.59,4.59));
@P *= xform;

