// PC Open / Flocking Logic 1
int pc = pcopen(0, 'P', @P, 0.8, 31);
vector center = set(0,0,0);
vector avoid = set(0,0,0);
int count = 0;
while(pciterate(pc)) {
    vector p;
    pcimport(pc, 'P', p);
    float d = distance(@P, p);
    center += p;
    if(d > 0.001 && d < 0.4) avoid += normalize(@P - p) / d;
    count++;
}
pcclose(pc);
if(count > 0) {
    center /= count;
    @v += normalize(center - @P) * 0.1;
    @v += avoid * 0.15;
}

